// Generates SQL to create/update the single admin user with a PBKDF2 hash.
// The hashing here MUST match src/lib/auth.ts (scheme/iterations/format).
//
// Usage:
//   node scripts/set-admin-password.mjs <email> <password>
// then apply the generated file:
//   npx wrangler d1 execute donutville --local  --file=drizzle/admin-user.sql
//   npx wrangler d1 execute donutville --remote --file=drizzle/admin-user.sql
import { webcrypto as crypto } from "node:crypto";
import { writeFileSync, mkdirSync } from "node:fs";

const [email, password] = process.argv.slice(2);
if (!email || !password) {
  console.error("Usage: node scripts/set-admin-password.mjs <email> <password>");
  process.exit(1);
}

const ITERATIONS = 100_000;
const SALT_BYTES = 16;
const KEY_BITS = 256;

async function pbkdf2(pw, salt) {
  const keyMaterial = await crypto.subtle.importKey(
    "raw",
    new TextEncoder().encode(pw),
    "PBKDF2",
    false,
    ["deriveBits"],
  );
  const bits = await crypto.subtle.deriveBits(
    { name: "PBKDF2", salt, iterations: ITERATIONS, hash: "SHA-256" },
    keyMaterial,
    KEY_BITS,
  );
  return new Uint8Array(bits);
}

const salt = crypto.getRandomValues(new Uint8Array(SALT_BYTES));
const hash = await pbkdf2(password, salt);
const b64 = (b) => Buffer.from(b).toString("base64");
const stored = `pbkdf2$${ITERATIONS}$${b64(salt)}$${b64(hash)}`;

const now = new Date().toISOString();
const safeEmail = email.toLowerCase().replace(/'/g, "''");
const sql = `-- Generated by scripts/set-admin-password.mjs — do not commit.
INSERT INTO admin_users (email, password_hash, created_at, updated_at)
VALUES ('${safeEmail}', '${stored}', '${now}', '${now}')
ON CONFLICT(email) DO UPDATE SET
  password_hash = excluded.password_hash,
  updated_at = excluded.updated_at;
`;

mkdirSync("drizzle", { recursive: true });
writeFileSync("drizzle/admin-user.sql", sql);

console.log(`Wrote drizzle/admin-user.sql for ${safeEmail}`);
console.log("Apply locally:  npx wrangler d1 execute donutville --local  --file=drizzle/admin-user.sql");
console.log("Apply remote:   npx wrangler d1 execute donutville --remote --file=drizzle/admin-user.sql");
